    output[i] = '\0';

    // Skip the delimiter if present
    if (*ptr == ',') {
        ptr++;
    }

    // Return NULL if we've reached the end, otherwise return pointer to next field
    return (*ptr == '\0' || *ptr == '\n' || *ptr == '\r') ? NULL : ptr;
}

int parse_csv_records(int record_count, int* field_sizes, char** csv_data, char** parsed_buffer) {
    // Input validation
    if (record_count <= 0 || record_count > INT_MAX / 1024) {
        return -1;
    }

    if (field_sizes == NULL || csv_data == NULL || parsed_buffer == NULL) {
        return -1;
    }

    // Count number of fields by checking the first CSV record
    int num_fields = 0;
    if (csv_data[0] != NULL) {
        char* ptr = csv_data[0];
        num_fields = 1;  // At least one field
        while (*ptr != '\0' && *ptr != '\n' && *ptr != '\r') {
            if (*ptr == ',') {
                num_fields++;
            }
            ptr++;
        }
    }

    if (num_fields == 0) {
        return -1;
    }

    // Calculate size for one record
    size_t record_size;
    if (calculate_record_size(field_sizes, num_fields, &record_size) != 0) {
        return -1;
    }

    // Calculate total buffer size
    size_t total_size;
    if (safe_mul_size(record_size, (size_t)record_count, &total_size) != 0) {
        return -1;
    }

    // Add some extra space for safety and alignment
    size_t final_size;
    if (safe_add_size(total_size, 64, &final_size) != 0) {
        return -1;
    }

    // Allocate memory
    char* buffer = (char*)calloc(final_size, sizeof(char));
    if (buffer == NULL) {
        return -1;
    }

    // Parse CSV data
    size_t buffer_offset = 0;

    for (int rec = 0; rec < record_count; rec++) {
        if (csv_data[rec] == NULL) {
            free(buffer);
            return -1;
        }

        char* line_ptr = csv_data[rec];

        for (int field = 0; field < num_fields; field++) {
            size_t field_size = (size_t)field_sizes[field] + 1;  // +1 for null terminator

            // Check if we have enough space
            if (buffer_offset + field_size > final_size) {
                free(buffer);
                return -1;
            }

            // Parse the field
            if (line_ptr != NULL) {
                line_ptr = parse_field(line_ptr, buffer + buffer_offset, field_size);
            } else {
                // No more fields in this line, fill with empty string
                buffer[buffer_offset] = '\0';
            }

            buffer_offset += field_size;
        }
    }

    *parsed_buffer = buffer;
    return 0;
}
